package external

import (
	"context"
	"time"
)

// DiscountIssuer creates and revokes discounts on the payment provider so
// that codes generated by the trial-rewards system can be applied at
// checkout.
//
// Implementations are expected to be idempotent on (code, variantID) — if a
// discount already exists for the same code/variant pair, returning the
// existing external ID is preferred over erroring.
type DiscountIssuer interface {
	// IssueDiscount creates a single-redemption percentage discount with the
	// given code on the given variant, expiring at expiresAt. Returns the
	// payment-provider's discount ID.
	IssueDiscount(ctx context.Context, code string, percentOff int, variantID string, expiresAt time.Time) (externalID string, err error)

	// RevokeDiscount removes a previously-issued discount from the payment
	// provider so it can no longer be redeemed at checkout. Used when a
	// higher tier supersedes a lower one — only the latest tier's code
	// remains active for the user. Idempotent: revoking an unknown or
	// already-deleted ID should not error.
	RevokeDiscount(ctx context.Context, externalID string) error
}
